/** Clears all curriculum data and recreates it. Destructive — erases student progress. */
export async function seedDatabase() {
  await prisma.courseEnrollment.deleteMany()
  await prisma.lessonAttempt.deleteMany()
  await prisma.lesson.deleteMany()
  await prisma.section.deleteMany()
  await prisma.classroomCourse.deleteMany()
  await prisma.course.deleteMany()

  await prisma.course.create({
    data: {
      title: 'Typing Fundamentals',
      subtitle: 'Master touch typing from home row to high speed.',
      icon: '⌨️',
      accent: 'mint',
      isPublic: true,
      order: 0,
      sections: {
        create: [
          { title: 'Home Row', description: 'Master the eight home row keys: A S D F J K L ;', order: 0, lessons: { create: homeRow } },
          { title: 'Top Row', description: 'Add Q W E R T Y U I O P to your home row foundation.', order: 1, lessons: { create: topRow } },
          { title: 'Bottom Row', description: 'Complete the alphabet with Z X C V B N M and punctuation.', order: 2, lessons: { create: bottomRow } },
          { title: 'Common Words', description: 'Build speed and fluency with high-frequency English text.', order: 3, lessons: { create: commonWords } },
          { title: 'Speed Building', description: 'Push your limits with longer passages from classic literature and beyond.', order: 4, lessons: { create: speedBuilding } },
        ],
      },
    },
  })

  await prisma.course.create({
    data: {
      title: `Alice's Adventures in Wonderland`,
      subtitle: 'Follow Alice down the rabbit hole — one paragraph at a time.',
      icon: '🐇',
      accent: 'berry',
      isPublic: true,
      order: 1,
      sections: {
        create: [
          { title: 'Ch. 1 — Down the Rabbit-Hole',     description: 'Alice follows a white rabbit into a very deep hole.', order: 0,  lessons: { create: alice1 } },
          { title: 'Ch. 2 — The Pool of Tears',        description: 'Alice grows too large, then too small, then swims away.', order: 1,  lessons: { create: alice2 } },
          { title: 'Ch. 3 — A Caucus-Race',            description: 'Wet creatures run a very strange race with no winner.', order: 2,  lessons: { create: alice3 } },
          { title: 'Ch. 4 — The Rabbit Sends in Bill', description: 'Alice gets stuck in a tiny house and makes a daring escape.', order: 3,  lessons: { create: alice4 } },
          { title: 'Ch. 5 — Advice from a Caterpillar', description: 'A blue caterpillar asks Alice a question she cannot answer.', order: 4,  lessons: { create: alice5 } },
          { title: 'Ch. 6 — Pig and Pepper',           description: 'Alice visits a duchess, a cook, and a grinning cat.', order: 5,  lessons: { create: alice6 } },
          { title: 'Ch. 7 — A Mad Tea-Party',          description: 'Alice joins the Hatter and March Hare for a very odd tea.', order: 6,  lessons: { create: alice7 } },
          { title: "Ch. 8 — The Queen's Croquet-Ground", description: 'The Queen plays croquet with flamingos and hedgehogs.', order: 7,  lessons: { create: alice8 } },
          { title: "Ch. 9 — The Mock Turtle's Story",  description: 'A sad Mock Turtle tells Alice about school under the sea.', order: 8,  lessons: { create: alice9 } },
          { title: 'Ch. 10 — The Lobster Quadrille',   description: 'Alice learns a very splashy and confusing dance.', order: 9,  lessons: { create: alice10 } },
          { title: 'Ch. 11 — Who Stole the Tarts?',    description: 'The Knave of Hearts stands trial for stealing tarts.', order: 10, lessons: { create: alice11 } },
          { title: "Ch. 12 — Alice's Evidence",        description: 'Alice stands up to the Queen and wakes from her dream.', order: 11, lessons: { create: alice12 } },
        ],
      },
    },
  })

  console.log('Seeded 250 core lessons + 72 Alice in Wonderland lessons across 17 sections.')
}
